<div class="d-flex justify-content-between align-items-center mb-3 mobile-stack"><div><h1 class="page-title h3 mb-1">Penjualan</h1><div class="text-muted">Kelola transaksi penjualan, lacak invoice, dan telusuri histori perubahan dengan cepat.</div></div><div class="mobile-stack"><?php if (has_role('super_admin','admin_umkm')): ?><a class="btn btn-outline-secondary" href="<?= e(url('index.php?page=penjualan-history')) ?>">Riwayat Perubahan</a><?php endif; ?><a class="btn btn-primary" href="<?= e(url('index.php?page=penjualan-create')) ?>"><i class="bi bi-plus-circle me-1"></i>Tambah Penjualan</a></div></div>
<div class="card enterprise-card mb-3"><div class="card-body"><form class="filter-grid" method="get"><input type="hidden" name="page" value="penjualan"><div><label class="form-label">Cari cepat</label><input class="form-control" name="q" value="<?= e($filters['q'] ?? '') ?>" placeholder="Kode, pelanggan, petugas"></div><div><label class="form-label">Dari tanggal</label><input type="date" class="form-control" name="date_from" value="<?= e($filters['date_from'] ?? '') ?>"></div><div><label class="form-label">Sampai tanggal</label><input type="date" class="form-control" name="date_to" value="<?= e($filters['date_to'] ?? '') ?>"></div><div class="d-flex align-items-end gap-2"><button class="btn btn-dark flex-fill">Filter</button><a class="btn btn-outline-secondary" href="<?= e(url('index.php?page=penjualan')) ?>">Reset</a></div></form></div></div>
<div class="row g-3 mb-3"><div class="col-12 col-md-4"><div class="card enterprise-card h-100"><div class="card-body"><div class="text-muted small">Jumlah Total</div><div class="h5 mb-0"><?= e(fmt_rp((int)($summary['total'] ?? 0))) ?></div></div></div></div><div class="col-12 col-md-4"><div class="card enterprise-card h-100"><div class="card-body"><div class="text-muted small">Jumlah Dibayar</div><div class="h5 mb-0"><?= e(fmt_rp((int)($summary['dibayar'] ?? 0))) ?></div></div></div></div><div class="col-12 col-md-4"><div class="card enterprise-card h-100"><div class="card-body"><div class="text-muted small">Jumlah Sisa</div><div class="h5 mb-0"><?= e(fmt_rp((int)($summary['sisa'] ?? 0))) ?></div></div></div></div></div>
<div class="card enterprise-card"><div class="card-body p-0"><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>No</th><th>Kode</th><th>Tanggal</th><th>Pelanggan</th><th class="text-end">Total</th><th class="text-end">Dibayar</th><th class="text-end">Sisa</th><th>Status</th><th class="text-end">Aksi</th></tr></thead><tbody><?php if (!$rows): ?><tr><td colspan="9" class="text-center text-muted py-5">Belum ada data penjualan untuk filter yang dipilih.</td></tr><?php endif; ?><?php foreach($rows as $i => $r): ?><tr><td><?= $i + 1 ?></td><td><span class="badge rounded-pill text-bg-light"><?= e($r['kode_penjualan']) ?></span></td><td><?= e(date('d-m-Y H:i', strtotime($r['tanggal']))) ?></td><td><?= e($r['nama_pelanggan'] ?? '-') ?></td><td class="text-end"><?= e(fmt_rp($r['total'])) ?></td><td class="text-end"><?= e(fmt_rp($r['dibayar'])) ?></td><td class="text-end"><?= e(fmt_rp($r['sisa'])) ?></td><td><span class="badge <?= $r['status_pembayaran']==='lunas' ? 'text-bg-success' : ($r['status_pembayaran']==='sebagian' ? 'text-bg-warning' : 'text-bg-danger') ?>"><?= e($r['status_pembayaran']) ?></span></td><td class="text-end"><div class="mobile-stack justify-content-end"><a class="btn btn-sm btn-outline-dark" href="<?= e(url('index.php?page=penjualan-show&id='.$r['id'])) ?>">Detail</a><a class="btn btn-sm btn-outline-primary" href="<?= e(url('index.php?page=penjualan-edit&id='.$r['id'])) ?>">Edit</a><a class="btn btn-sm btn-outline-secondary" target="_blank" href="<?= e(url('index.php?page=penjualan-invoice&id='.$r['id'])) ?>">Invoice</a><?php if (has_role('super_admin','admin_umkm')): ?><form method="post" action="<?= e(url('index.php?page=penjualan-delete')) ?>" class="d-inline" onsubmit="return confirm('Hapus transaksi <?= e(addslashes($r['kode_penjualan'])) ?>?');"><input type="hidden" name="_csrf" value="<?= e(csrf_token()) ?>"><input type="hidden" name="id" value="<?= (int)$r['id'] ?>"><button type="submit" class="btn btn-sm btn-outline-danger">Hapus</button></form><?php endif; ?></div></td></tr><?php endforeach; ?></tbody></table></div></div></div>
